-- Best Music Venues in NYC  (5 chapters, 2 sections)
do $$
declare v_story uuid; v_owner uuid;
  v_sec0 uuid;
  v_sec1 uuid;
begin
  select id into v_owner from auth.users where email='michael.o.mccann@gmail.com' limit 1;
  delete from public.stories where slug='best-music-venues-in-nyc';
  insert into public.stories(title,slug,status,published_at,owner_id)
  values ('Best Music Venues in NYC','best-music-venues-in-nyc','published',now(),v_owner) returning id into v_story;
  insert into public.sections(story_id,name,position) values (v_story,'Manhattan',0) returning id into v_sec0;
  insert into public.sections(story_id,name,position) values (v_story,'Brooklyn',1) returning id into v_sec1;
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec0,1,'Beacon Theatre','Uber Spacious','This spacious former vaudeville theater, resplendent after a recent renovation, hosts a variety of popular acts, from Steely Dan to Ryan Adams. While the vastness can seem daunting for performers and audience members alike, the gaudy interior and uptown location make you feel as though you’re having a real night out on the town.',
    array['Best Music Venues in NYC']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/6626d1f327df43ed9ce42390_Ivn-WdXKBsg3oT3XyHE4G5XsI-Vk2dko7C4fefDHGm0.webp','Upper West Side, Manhattan',-73.979417,40.778059,jsonb_build_object('zoom',13.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec1,2,'Music Hall of Williamsburg','Cool Venue','Run by local promoter Bowery Presents, this Williamsburg outpost is basically a mirror image of similarly sized Bowery Ballroom, one upping its Manhattan counterpart with improved sightlights—including elevated areas on either side of the room—and a bit more breathing room. With booking that ranges from indie-rock bands to hip-hop acts, it''s one of the best rooms in New York to see a show.',
    array['Best Music Venues in NYC']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/6626d1f2acd99b30448fd4cc_M9EAIcGVRgILGfxXedE9pGzOvAjSbvmnUMRwXhxH5RU.webp','Williamsburg, Brooklyn',-73.96169,40.719272,jsonb_build_object('zoom',13.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec1,3,'Saint Vitus','The trendies hang out here','This Greenpoint club—moodily decorated with all-black walls and dead roses hanging above the bar—is one of the best places in the city to see metal, rock and more experimental heavy music, with reliably loud bands typically booked seven nights a week.',
    array['Best Music Venues in NYC']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/6626d1f2ebfbd608772b5a89_8ckS4R2sLPmS80BTyL-QvUZcDF964hK28Rwj8L9FWks.webp','Greenpoint, Brooklyn',-73.947367,40.738202,jsonb_build_object('zoom',13.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec0,4,'Village Vanguard','Old School Vibes','After more than 80 years, this basement club’s stage still hosts the crème de la crème of mainstream jazz talent. Plenty of history has been made here—John Coltrane, Miles Davis and Bill Evans have grooved in this hallowed hall—and the 16-piece Vanguard Jazz Orchestra has been the Monday-night regular since 1966. Thanks to the venue''s strict no cell phone policy, seeing a show here feels like stepping back and time. It''s just you and the music.',
    array['Best Music Venues in NYC']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/6626d1f130118eb4bb5fcf82_AlvtOTTH5Ronm11PAoRHF89HaT_S08ykJh4z3_DCr6o.webp','West Village, Manhattan',-74.003144,40.734608,jsonb_build_object('zoom',13.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec1,5,'Elsewhere','Booming Sound System','Operated by the hip folks behind beloved art and music haven Glasslands, this 24,000 square-foot converted warehouse hosts live shows and DJ nights on three stages: two inside and one rooftop space. Its bookings feature a diverse mix of cutting-edge indie-rock, electronic music and more.',
    array['Best Music Venues in NYC']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/6626d1f016ba7e50b4963cc7_Nw0mn2DvbGALeCczS4LMbSjX58Bw6i54mrwo1gXVtZo.webp','East Williamsburg, Brooklyn',-73.923855,40.708397,jsonb_build_object('zoom',13.0,'pitch',60.0,'bearing',-10.0));
end $$;

-- 7 Wonders  (8 chapters, 8 sections)
do $$
declare v_story uuid; v_owner uuid;
  v_sec0 uuid;
  v_sec1 uuid;
  v_sec2 uuid;
  v_sec3 uuid;
  v_sec4 uuid;
  v_sec5 uuid;
  v_sec6 uuid;
  v_sec7 uuid;
begin
  select id into v_owner from auth.users where email='michael.o.mccann@gmail.com' limit 1;
  delete from public.stories where slug='7-wonders';
  insert into public.stories(title,slug,status,published_at,owner_id)
  values ('7 Wonders','7-wonders','published',now(),v_owner) returning id into v_story;
  insert into public.sections(story_id,name,position) values (v_story,'China',0) returning id into v_sec0;
  insert into public.sections(story_id,name,position) values (v_story,'India',1) returning id into v_sec1;
  insert into public.sections(story_id,name,position) values (v_story,'Jordan',2) returning id into v_sec2;
  insert into public.sections(story_id,name,position) values (v_story,'Italy',3) returning id into v_sec3;
  insert into public.sections(story_id,name,position) values (v_story,'Mexico',4) returning id into v_sec4;
  insert into public.sections(story_id,name,position) values (v_story,'Peru',5) returning id into v_sec5;
  insert into public.sections(story_id,name,position) values (v_story,'Brazil',6) returning id into v_sec6;
  insert into public.sections(story_id,name,position) values (v_story,'All',7) returning id into v_sec7;
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec0,1,'The Great Wall of China','The longest wall in the world','The Great Wall of China is the longest wall in the world! The Chinese national symbol was built by several dynasties (ruling families) over hundreds of years (nearly 1,800), starting in about 220 BC. The wall was built to defend areas from invasions and had watchtowers built on the highest places. The famous landmark is actually made up of lots of overlapping walls that measure a combined length of up to 20,000 kilometres. Millions of people visit the Wonder every year.',
    array['7 Wonders']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/66281348881c51a16082208a_phU9pRDjzGFyCryiDaiev1QK0M8F6cybkYhIjqd9zE4.webp','Huairou District, China',116.538709,40.281243,jsonb_build_object('zoom',5.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec1,2,'Taj Mahal','16 years and 20,000 workers to build!','This magnificent landmark took 16 years and 20,000 workers to build! It was commissioned to be built in 1632 by Emperor Shah Jahan with the purpose of housing the tomb of his wife, Mumtaz. Architecturally, the building represents symmetry and balance, and the colour of the exterior marble walls change depending on the time of day. In the morning sun, the white marble looks a shade of pink. During the evening, it looks the colour of milk and looks golden at night when lit by the moon. Because the Taj Mahal commemorates Shah Jahan’s love for Mumtaz, couples like to have their photographs taken with the building in the background.',
    array['7 Wonders']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/6628134769db3e1537daf3da_BMFN6000s7Y5cxFcGGnR_Eq_Sd8zXWKndJektP7Z_Uo.webp','Agra, India',78.0421,27.1751,jsonb_build_object('zoom',18.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec2,3,'Petra','An ancient city carved into rock.','It is thought that it was built over 2,000 years ago by a group of people who lived in the Wadi Musa valley, called the Nabateans. However, not much is known about the Nabateans. The city fell to the Roman Empire in AD 106 and an earthquake in AD 363 damaged the city, which resulted in it eventually falling into disuse. The city ruins were rediscovered in 1812 by a Swiss explorer called Johann Burckhardt.',
    array['7 Wonders']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/66281346cab9cd645ec3030b_55rSReQ8y3s30hj-vonobONBGxchUeuJnId9BdxR0Y4.webp','Petra, Jordan',35.4444,30.3285,jsonb_build_object('zoom',18.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec3,4,'The Colosseum','AKA Flavian Amphitheatre','The Colosseum, was built between AD 70 and AD 80. It was used for gladiator fights, animal hunts and public executions for four centuries. The floor could also be flooded in order to stage sea battles! Following the fall of the Roman Empire, the architectural masterpiece was actually used as a housing complex. Then, in 1349, a great earthquake destroyed parts of the structure. Despite the damage done over the years, it remains an incredibly popular tourist attraction today.',
    array['7 Wonders']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/660ff47a0acf1e152362fb82_DjeC0xsHTlJ-gk2Hp-4uhXlezRz7HpJbk4nNko1wBj8.webp','Rome, Italy',12.4922,41.8902,jsonb_build_object('zoom',18.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec4,5,'Temple of Kukulcan, Chichén Itzá','Built over 1500 years ago','Chichén Itzá was a city built by The Maya people over 1,500 years ago. The city was an important political and economic centre for The Maya people.',
    array['7 Wonders']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/660ff47ae0c92a5a3e9c05ad_xVx46-9b19sKmN9_3_Ji9sMUTEmD6eIWJ2FhnRQ_dkY.webp','Chichén Itzá, Mexico',-88.568615,20.682907,jsonb_build_object('zoom',18.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec5,6,'Machu Picchu','Situated 2,000 meters above sea level','Machu Picchu is the ruins of a city from the Incan empire that was built in the 15th century. The ruins are in the Andes Mountains, over 2,000 metres above sea level. Its walls and other architectural elements are cut into the natural rock. It’s not certain why the city was first built, although some sources suggest it was used as a royal retreat for the emperor, Pachacuti Inca Yupanqui. It is thought to have been used between the 15th and 16th centuries, but was gradually abandoned over time. Today, it is a very popular tourist site, so much so that the Peruvian government has begun limiting the amount of people able to visit each year to preserve it.',
    array['7 Wonders']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/660f57dc249f7f94f4987ec4_3NfPoppkO05mZt3AGMJESjXoNSAY8p9yIhYjjIQSbdU.webp','Cusco, Peru',-72.491894,-13.208907,jsonb_build_object('zoom',18.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec6,7,'Christ the Redeemer','Standing 30m tall arms spanning of 28m','Christ the Redeemer is a statue located at the summit of Corcovado Mountain overlooking Rio de Janeiro in Brazil. The statue shows Jesus Christ with his arms spread out over the city. The statue is 30 meters tall, with an arm span of the statue is 28 meters! The structure is the newest wonder, having been completed in 1931. At the time of its construction, Brazil was a predominantly Catholic country, and images of the Christ statue were spread throughout.',
    array['7 Wonders']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/660f57db6e9cdc943317091e_rm2pEuBGDqHiOLheCT-I_OCaOBxTvAebvG-A6-zXK2c.webp','Rio de Janeiro, Brazil',-43.262064,-22.940028,jsonb_build_object('zoom',18.0,'pitch',60.0,'bearing',-10.0));
  insert into public.chapters(story_id,section_id,position,name,headline,body,tags,image_url,place_name,longitude,latitude,camera) values (
    v_story,v_sec7,8,'Seven Wonders','','',
    array['7 Wonders']::text[],'https://uploads-ssl.webflow.com/64ea1f05f055c6958cd93deb/6628133d349966cb5ebc01d3_5KdWjVogkStwRGj-u1p_qeafDch6H5gLAFIaEOxvvWk.webp',null,-43.262064,-22.940028,jsonb_build_object('zoom',13.0,'pitch',60.0,'bearing',-10.0));
end $$;

